VALUES
  ('social-worker-moex-00531', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '甲老先生家中的孩子都已經各自成家，他與太太調適著家庭的變化、適應空巢期，並培養新興趣， 也努力讓年輕一代有更加安全、有意義和令人滿意的生活，並且積極面對健康和老化問題，建設 性地面對死亡。甲老先生的心態符合下列那一種理論的描述？', '["脫離理論", "連續理論", "自我統整理論", "社會交換理論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00532', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '某位青少女案主很難獨立，不容易建立成熟的親密關係、面對職涯無法選擇、拒絕擔負更多責任 的職位和機會。作為服務青少年的社會工作者，應如何介入服務？', '["協助削弱人際界線", "協助強化情感投射", "協助案主堅持己見", "協助培養獨立自主"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00533', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '生命歷程的觀點聚焦在了解生活型態的變化，關於這個觀點，下列敘述何者錯誤？', '["各個生命歷程的階段都有其所屬的風險因子和保護因子", "以軌跡的概念了解人們所遵循的環境或社會路徑", "評估一個特殊事件發生的時間，試圖評估該事件對個人生命軌跡的影響和衝擊", "生命歷程屬於一種社會化的制度，並不會受到社會變動主要過程的影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00534', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '成年前期處於親密與疏離的階段，某些人會加入宗教組織，尋求心靈相近的同伴，也就是藉由信仰 協助他們建立親密關係。這種用來解釋人們在不同階段參與宗教活動的觀點，屬於下列何種理論？', '["社會學習理論", "信仰發展理論", "心理社會發展理論", "社會建構理論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00535', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對育兒者而言，下列那一個教養態度不利於兒童早期的性別角色探索？', '["由育兒者示範男女在家庭和社會的固定性別角色功能", "兒童教育應兼有兩性特質（androgyny）的性別取向", "對兒童的「自慰性遊戲」保持平常心，並予以適時引導", "教導兒童區別公眾的我與私下的我，有利於預防性虐待"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00536', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對初為人父的男性而言，關於父親與嬰兒的關係，下列敘述何者錯誤？', '["常與孩子在一起的父親，和母親一樣能解讀孩子的訊息", "有些男性初次擔任父親角色時也會有產後憂鬱", "從依附關係來看，父親也可以擔任嬰幼兒的主要照顧者", "嬰兒和父親的依附發展方式與過程，與母親有極大差異"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00537', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '建構保障婦女就業的平權法案時，下列相關理論的敘述，何者錯誤？', '["效益理論：解釋即便因優待某些人而犧牲另一些人，其結果對社會仍有價值", "社會正義理論：強調每個人應享有平等的權利與資源，降低性別差異", "歧視相關理論：解釋許多性別與種族在社會上的就業機會不平等", "自由主義觀點的正義理論：政府應強力干預企業在婦女就業上的保障"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00538', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '酷兒理論的發展始於1980年代後期，針對此理論的描述，下列何者錯誤？', '["應檢視社會對正常的定義如何病態化「不正常行為」", "應重新檢視異性戀定義，及異性戀／同性戀的二分法", "用以區辨那些人需要接受性別矯正，以協助其正常化", "藉由重新檢視讓人得以改變對人類行為的認知與態度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00539', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '運用「種族主義」此概念在社會工作實踐時，不包含下列那個層面的思考？', '["個人種族主義", "制度種族主義", "環境種族主義", "經濟種族主義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00540', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '微侵略（microaggressions）是種族主義、歧視和偏見等常見的表現形式。下列敘述何者錯誤？', '["可分為微攻擊、微侮辱、微排擠、環境的微攻擊等四大類", "通常會藉由傳送負面的且微妙的訊息給他人以維持偏見、歧視與壓迫", "「她可真是個聰明的原住民女學生」僅是單純稱讚，不算微侵略", "可辨別的種族、民族或少數群體的人們，常是微侵略的目標族群"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
